/* The crossing itself. The slot address is parked in __rc2/3 before
 * anything moves; $22-$25 ride the hardware stack -- and so does the
 * compiler's whole imaginary-register file at $02-$21: clang keeps
 * live values there across this call (its clobber list cannot say
 * otherwise for zero page), while any slot that reaches the KERNAL --
 * the text mode, the loaders, the DOS glue -- scribbles that range as
 * the KERNAL's own r0-r15. One string pointer held in __rc6/7 across
 * a cx_say was enough to print garbage; now the crossing preserves
 * the lot, exactly as the kernel's event IRQ does around itself. The
 * mirror is copied in, A/X/Y loaded, the slot called through a
 * trampoline, and registers, carry and the block all copied back. */
__attribute__((weak, noinline)) void cx_run(void) {
    asm volatile(
        "lda cx_slot\n\t"
        "sta __rc2\n\t"
        "lda cx_slot+1\n\t"
        "sta __rc3\n\t"
        "lda 0x22\n\tpha\n\t"
        "lda 0x23\n\tpha\n\t"
        "lda 0x24\n\tpha\n\t"
        "lda 0x25\n\tpha\n\t"
        "ldy #0x1f\n\t"
        "5:\n\t"
        "lda 0x02,y\n\t"
        "pha\n\t"
        "dey\n\t"
        "bpl 5b\n\t"
        "ldy #7\n\t"
        "1:\n\t"
        "lda cx_p,y\n\t"
        "sta 0x22,y\n\t"
        "dey\n\t"
        "bpl 1b\n\t"
        "ldy cx_y\n\t"
        "ldx cx_x\n\t"
        "lda cx_a\n\t"
        "jsr 2f\n\t"
        "sta cx_a\n\t"
        "stx cx_x\n\t"
        "php\n\t"
        "pla\n\t"
        "and #1\n\t"
        "sta cx_c\n\t"
        "ldy #7\n\t"
        "3:\n\t"
        "lda 0x22,y\n\t"
        "sta cx_p,y\n\t"
        "dey\n\t"
        "bpl 3b\n\t"
        "ldy #0\n\t"
        "6:\n\t"
        "pla\n\t"
        "sta 0x02,y\n\t"
        "iny\n\t"
        "cpy #0x20\n\t"
        "bne 6b\n\t"
        "pla\n\tsta 0x25\n\t"
        "pla\n\tsta 0x24\n\t"
        "pla\n\tsta 0x23\n\t"
        "pla\n\tsta 0x22\n\t"
        "bra 4f\n\t"
        "2:\n\t"
        "jmp (__rc2)\n\t"
        "4:"
        ::: "a", "x", "y", "cc", "memory");
}

